class Queue:
    def __init__(self):
        self.last = None

    def isEmpty(self):
        return self.last is None

    def head(self):
        return self.last

    def enqueue(self, x):
        self.last = x

    def dequeue(self):
        v = self.last
        self.last = None
        return v

public int Calculator(String[] input, IntegerStack s) {
    for (int i = 0; i < input.length; ++i) {
        switch (input[i]) {
            case "+":
                { int n1 = s.pop(); int n2 = s.pop(); s.push(n2 + n1); }
                break;
            case "-":
                { int n1 = s.pop(); int n2 = s.pop(); s.push(n2 - n1); }
                break;
            case "*":
                { int n1 = s.pop(); int n2 = s.pop(); s.push(n2 * n1); }
                break;
            case "/":
                { int n1 = s.pop(); int n2 = s.pop(); s.push(n2 / n1); }
                break;
            default:
                s.push(Integer.parseInt(input[i]));
                break;
        }
    }
    return s.pop();
}

