def Calculator(inputarray, stack):
    for i in inputarray:
        if i == '+':
            n1 = stack.pop(); n2 = stack.pop(); stack.push(n2 + n1)
        elif i == '-':
            n1 = stack.pop(); n2 = stack.pop(); stack.push(n2 - n1)
        elif i == '*':
            n1 = stack.pop(); n2 = stack.pop(); stack.push(n2 * n1)
        elif i == '/':
            n1 = stack.pop(); n2 = stack.pop(); stack.push(n2 / n1)
        else:
            stack.push(int(i))
    return stack.pop()

