public Node delete(Node root, Node delete) {
    Node y = null;
    if (delete.left == null || delete.right == null) {
        y = delete;
    } else {
        y = treeMinimum(delete.right);
    }
    Node x = null;
    if (y.left != null) x = y.left;
    else x = y.right;
    if (x != null) x.parent = y.parent;
    if (y.parent == null) {
        root = x;
    } else {
        if (y == y.parent.left) y.parent.left = x;
        else y.parent.right = x;
    }
    if (y != delete) delete.key = y.key;
    return root;
}

public Node treeMinimum(Node n) {
    while (n.left != null) n = n.left;
    return n;
}

// Handles leaf and one-child cases only; two-child case is broken (no successor)
public Node delete(Node root, Node delete) {
    Node x = (delete.left != null) ? delete.left : delete.right;
    if (x != null) x.parent = delete.parent;
    if (delete.parent == null) {
        root = x;
    } else {
        if (delete == delete.parent.left) delete.parent.left = x;
        else delete.parent.right = x;
    }
    return root;
}

