def tree_minimum(n):
    while n.left is not None:
        n = n.left
    return n

def delete(root, delete):
    if delete.left is None or delete.right is None:
        y = delete
    else:
        y = tree_minimum(delete.right)
    x = y.left if y.left is not None else y.right
    if x is not None:
        x.parent = y.parent
    if y.parent is None:
        root = x
    else:
        if y is y.parent.left:
            y.parent.left = x
        else:
            y.parent.right = x
    if y is not delete:
        delete.key = y.key
    return root

