public List<Integer> bfs(int[][] graph, int start) {
    List<Integer> visited = new ArrayList<Integer>();
    List<Integer> queue = new ArrayList<Integer>();
    queue.add(start);
    while (!queue.isEmpty()) {
        int next = queue.remove(0);
        if (!visited.contains(next)) {
            visited.add(next);
            for (int vertex : graph[next]) {
                if (!visited.contains(vertex)) queue.add(vertex);
            }
        }
    }
    return visited;
}

// Pops from the end of the queue - effectively DFS, not BFS
public List<Integer> bfs(int[][] graph, int start) {
    List<Integer> visited = new ArrayList<Integer>();
    List<Integer> queue = new ArrayList<Integer>();
    queue.add(start);
    while (!queue.isEmpty()) {
        int next = queue.remove(queue.size() - 1);
        if (!visited.contains(next)) {
            visited.add(next);
            for (int vertex : graph[next]) {
                if (!visited.contains(vertex)) queue.add(vertex);
            }
        }
    }
    return visited;
}

