def bfs(graph, start):
    visited, queue = [], [start]
    while queue:
        nxt = queue.pop(0)
        if nxt not in visited:
            visited.append(nxt)
            for vertex in graph[nxt]:
                if vertex not in visited:
                    queue.append(vertex)
    return visited

