public List<Integer> dfs(int[][] graph, int start) {
    List<Integer> visited = new ArrayList<Integer>();
    Stack<Integer> stack = new Stack<Integer>();
    stack.push(start);
    while (!stack.isEmpty()) {
        int next = stack.pop();
        if (!visited.contains(next)) {
            visited.add(next);
            for (int i = graph[next].length - 1; i >= 0; --i) {
                if (!visited.contains(graph[next][i])) stack.push(graph[next][i]);
            }
        }
    }
    return visited;
}

// DFS structure but no visited check - infinite loop on cycles
public List<Integer> dfs(int[][] graph, int start) {
    List<Integer> visited = new ArrayList<Integer>();
    Stack<Integer> stack = new Stack<Integer>();
    stack.push(start);
    int safety = 0;
    while (!stack.isEmpty() && safety++ < 1000) {
        int next = stack.pop();
        visited.add(next);
        for (int i = graph[next].length - 1; i >= 0; --i) {
            stack.push(graph[next][i]);
        }
    }
    return visited;
}

