def dfs(graph, start):
    visited, stack = [], [start]
    while stack:
        nxt = stack.pop()
        if nxt not in visited:
            visited.append(nxt)
            for vertex in reversed(graph[nxt]):
                if vertex not in visited:
                    stack.append(vertex)
    return visited

