public int editDistance(String a, String b) {
    int m = a.length(), n = b.length();
    int[][] edDis = new int[m + 1][n + 1];
    for (int i = 0; i <= m; ++i) edDis[i][0] = i;
    for (int j = 0; j <= n; ++j) edDis[0][j] = j;
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (a.charAt(i - 1) == b.charAt(j - 1)) {
                edDis[i][j] = edDis[i - 1][j - 1];
            } else {
                edDis[i][j] = 1 + Math.min(Math.min(edDis[i][j - 1], edDis[i - 1][j]), edDis[i - 1][j - 1]);
            }
        }
    }
    return edDis[m][n];
}

// Wrong base case - all zeros instead of i and j
public int editDistance(String a, String b) {
    int m = a.length(), n = b.length();
    int[][] edDis = new int[m + 1][n + 1];
    // base case NOT initialised; defaults to 0
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (a.charAt(i - 1) == b.charAt(j - 1)) {
                edDis[i][j] = edDis[i - 1][j - 1];
            } else {
                edDis[i][j] = 1 + Math.min(Math.min(edDis[i][j - 1], edDis[i - 1][j]), edDis[i - 1][j - 1]);
            }
        }
    }
    return edDis[m][n];
}

