def editDistance(a, b):
    m, n = len(a), len(b)
    edDis = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        edDis[i][0] = i
    for j in range(n + 1):
        edDis[0][j] = j
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                edDis[i][j] = edDis[i - 1][j - 1]
            else:
                edDis[i][j] = 1 + min(edDis[i][j - 1], edDis[i - 1][j], edDis[i - 1][j - 1])
    return edDis[m][n]

