long expo(long a, long b, long c) {
    if (b == 0) {
        return 1 % c;
    } else if (b % 2 != 0) {
        return (a * expo(a, b - 1, c)) % c;
    } else {
        a = expo(a, b / 2, c) % c;
        return (a * a) % c;
    }
}

// Base case missing %c (fails when c == 1); odd case forgets to multiply by a.
long expo(long a, long b, long c) {
    if (b == 0) {
        return 1;
    } else if (b % 2 != 0) {
        return expo(a, b - 1, c) % c;
    } else {
        a = expo(a, b / 2, c) % c;
        return (a * a) % c;
    }
}

// Returns base case only - no recursion.
long expo(long a, long b, long c) {
    return 1 % c;
}

def expo(a, b, c):
    if b == 0:
        return 1 % c
    elif b % 2:
        return (a * expo(a, b - 1, c)) % c
    else:
        a = expo(a, b // 2, c) % c
        return (a * a) % c

