// Recursive divide-and-conquer ordering algorithm (merging two ordered halves).
int[] solution(int[] arr) {
    helper(arr, 0, arr.length - 1);
    return arr;
}

void helper(int[] a, int l, int r) {
    if (l < r) {
        int m = (l + r) / 2;
        helper(a, l, m);
        helper(a, m + 1, r);
        merge(a, l, m, r);
    }
}

void merge(int[] a, int l, int m, int r) {
    int[] tmp = new int[r - l + 1];
    int i = l, j = m + 1, k = 0;
    while (i <= m && j <= r) {
        if (a[i] <= a[j]) tmp[k++] = a[i++];
        else tmp[k++] = a[j++];
    }
    while (i <= m) tmp[k++] = a[i++];
    while (j <= r) tmp[k++] = a[j++];
    for (int x = 0; x < tmp.length; x++) a[l + x] = tmp[x];
}

// Partition-based ordering with fixed last-element pivot and incomplete partition
// (only swaps the first element if it exceeds the pivot).
int[] solution(int[] arr) {
    quick(arr, 0, arr.length - 1);
    return arr;
}

void quick(int[] a, int l, int r) {
    if (l < r) {
        int p = partition(a, l, r);
        quick(a, l, p - 1);
        quick(a, p + 1, r);
    }
}

int partition(int[] a, int l, int r) {
    int pivot = a[r];
    int i = l;
    if (a[i] > pivot) {
        int t = a[i];
        a[i] = a[r];
        a[r] = t;
    }
    return i;
}

// Returns the array unchanged.
int[] solution(int[] arr) {
    return arr;
}

import random as rand

def randPartition(A, l, r):
    i = rand.randint(l, r)
    A[i], A[r] = A[r], A[i]
    return partition(A, l, r)

def partition(A, l, r):
    x = A[r]
    i = l - 1
    for j in range(l, r):
        if A[j] <= x:
            i = i + 1
            A[i], A[j] = A[j], A[i]
    A[i + 1], A[r] = A[r], A[i + 1]
    return i + 1

def quick(A, l, r):
    if l < r:
        p = randPartition(A, l, r)
        quick(A, l, p - 1)
        quick(A, p + 1, r)

def solution(A):
    quick(A, 0, len(A) - 1)
    return A

# Partition-based ordering with fixed last-element pivot and incomplete partition
# (only swaps the first element if it exceeds the pivot).
def partition(A, l, r):
    pivot = A[r]
    i = l
    if A[i] > pivot:
        A[i], A[r] = A[r], A[i]
    return i

def quick(A, l, r):
    if l < r:
        p = partition(A, l, r)
        quick(A, l, p - 1)
        quick(A, p + 1, r)

def solution(A):
    quick(A, 0, len(A) - 1)
    return A

