public double knapSack(double[] values, int[] volumes, int capacity) {
    int n = values.length;
    double[][] Result = new double[n + 1][capacity + 1];
    for (int i = n - 1; i >= 0; i--) {
        for (int j = 0; j <= capacity; j++) {
            if (volumes[i] <= j) {
                Result[i][j] = Math.max(values[i] + Result[i + 1][j - volumes[i]], Result[i + 1][j]);
            } else {
                Result[i][j] = Result[i + 1][j];
            }
        }
    }
    return Result[0][capacity];
}

// Inner loop starts at j=1 (misses zero-capacity column); uses strict < for feasibility;
// recurrence references the current row instead of the previous (allows reusing items).
public double knapSack(double[] values, int[] volumes, int capacity) {
    int n = values.length;
    double[][] Result = new double[n + 1][capacity + 1];
    for (int i = n - 1; i >= 0; i--) {
        for (int j = 1; j <= capacity; j++) {
            if (volumes[i] < j) {
                Result[i][j] = Math.max(values[i] + Result[i][j - volumes[i]], Result[i][j]);
            } else {
                Result[i][j] = Result[i + 1][j];
            }
        }
    }
    return Result[0][capacity];
}

// Greedy single-pass: sums values of any item that individually fits in the full capacity.
public double knapSack(double[] values, int[] volumes, int capacity) {
    double total = 0;
    for (int i = 0; i < values.length; i++) {
        if (volumes[i] <= capacity) total += values[i];
    }
    return total;
}

def dfs(node, graph, memo):
    if len(graph[node]) == 0:
        return 0
    elif memo[node] != -1:
        return memo[node]
    else:
        sol = 0
        for child in graph[node]:
            sol = max(sol, dfs(child, graph, memo) + 1)
        memo[node] = sol
        return memo[node]

