int[] calc(int[] a, int[][] b) {
    int n = a.length;
    int[] c = new int[n];
    int[] d = new int[n];
    c[0] = a[0];
    for (int i = 1; i < n; i++) {
        c[i] = a[i] + c[i - 1];
    }
    for (int i = 0; i < n; i++) {
        if (b[i][0] - 1 >= 0) {
            d[i] = c[b[i][1]] - c[b[i][0] - 1];
        } else {
            d[i] = c[b[i][1]];
        }
    }
    return d;
}

// Prefix loop copies a[i] without accumulating C[i-1];
// range sum doesn't handle the l==0 edge case (accesses C[-1] when b[i][0] == 0).
int[] calc(int[] a, int[][] b) {
    int n = a.length;
    int[] c = new int[n];
    int[] d = new int[n];
    c[0] = a[0];
    for (int i = 1; i < n; i++) {
        c[i] = a[i];
    }
    for (int i = 0; i < n; i++) {
        d[i] = c[b[i][1]] - c[b[i][0] - 1];
    }
    return d;
}

