long opt(long[] W) {
    int n = W.length - 1;
    long[] memo = new long[n + 1];
    for (int i = 0; i < n + 1; i++) memo[i] = -1;
    return opt_helper(n, W, memo);
}

long opt_helper(int n, long[] W, long[] memo) {
    if (n == 0) return W[0];
    if (n == 1) return Math.max(W[0], W[1]);
    if (memo[n] != -1) return memo[n];
    memo[n] = Math.max(W[n] + opt_helper(n - 2, W, memo), opt_helper(n - 1, W, memo));
    return memo[n];
}

// Memo initialised to 0 (default) with !=0 cache check; n==1 base case is missing.
long opt(long[] W) {
    int n = W.length - 1;
    long[] memo = new long[n + 1];
    return opt_helper(n, W, memo);
}

